curl -s --max-time 30 -X POST "https://ivx26-backend.rork.app/" -H "Content-Type: application/json" -d '{"action":"github-test"}' -o /tmp/bridge_test.json -w "BRIDGE_HTTP:%{http_code}\n"; node -e "
const j=require('/tmp/bridge_test.json');console.log(JSON.stringify(j).slice(0,800));
" 2>/dev/null | sed 's/gh[pousr]_[A-Za-z0-9_]*/[REDACTED]/g'

cd /tmp && node -e "
const tok=require('fs').readFileSync('/tmp/ghtok','utf8').trim();
const H={Authorization:'Bearer '+tok,'User-Agent':'ivx-deploy','Accept':'application/vnd.github+json'};
fetch('https://api.github.com/user',{headers:H}).then(async r=>{
  const b=await r.json().catch(()=>({}));
  console.log('GITHUB_USER_HTTP:'+r.status+' message:'+(b.message??'')+' doc:'+(b.documentation_url??'').slice(0,60));
});
"

